// Playwright Live Stack 功能验证脚本
const { chromium } = require('playwright');

(async () => {
  const results = {};
  const errors = [];

  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  // 捕获页面 JS 错误
  page.on('pageerror', (err) => {
    errors.push(`PAGE ERROR: ${err.message}`);
  });
  page.on('console', (msg) => {
    if (msg.type() === 'error') {
      errors.push(`CONSOLE ERROR: ${msg.text()}`);
    }
  });

  try {
    await page.goto('http://localhost:10280/', { waitUntil: 'networkidle', timeout: 15000 });
  } catch (e) {
    console.log(`⚠️  page goto warning: ${e.message}`);
  }

  // 截图
  await page.screenshot({ path: 'test_live_stack_screenshot.png', fullPage: true });

  // === 1. 主控台 Live Stack 控制栏是否显示 ===
  const liveStackSection = await page.$('text="Live Stack"');
  results['1_LiveStack控制栏'] = liveStackSection ? '✅ 存在' : '❌ 不存在';

  // === 2. 档位按钮是否可点击 ===
  const modes = ['off', '2s', '5s', '10s', '30s'];
  for (const mode of modes) {
    const btn = await page.$(`button[data-stack="${mode}"]`);
    if (btn) {
      const isVisible = await btn.isVisible();
      const isDisabled = await btn.isDisabled();
      // 尝试点击
      try {
        await btn.click();
        results[`2_档位_${mode}`] = `✅ 可见=${isVisible} 禁用=${isDisabled} 点击=成功`;
      } catch (e) {
        results[`2_档位_${mode}`] = `⚠️ 可见=${isVisible} 禁用=${isDisabled} 点击=失败: ${e.message}`;
      }
    } else {
      results[`2_档位_${mode}`] = '❌ 按钮不存在';
    }
  }

  // === 3. 硬件曝光输入框 ===
  const exposureInput = await page.$('#hardwareExposureMs');
  if (exposureInput) {
    const val = await exposureInput.inputValue();
    results['3_硬件曝光输入框'] = `✅ 存在，当前值=${val}`;
  } else {
    results['3_硬件曝光输入框'] = '❌ 不存在';
  }

  // === 4. 开始/停止/保存按钮 ===
  const startBtn = await page.$('#btnLiveStackStart');
  const stopBtn = await page.$('#btnLiveStackStop');
  const saveBtn = await page.$('#btnLiveStackSave');

  results['4_开始按钮'] = startBtn ? `✅ 存在, disabled=${await startBtn.isDisabled()}` : '❌ 不存在';
  results['4_停止按钮'] = stopBtn ? `✅ 存在, disabled=${await stopBtn.isDisabled()}` : '❌ 不存在';
  results['4_保存按钮'] = saveBtn ? `✅ 存在, disabled=${await saveBtn.isDisabled()}` : '❌ 不存在';

  // === 5. 点击档位按钮是否触发错误 ===
  // 先清空错误列表
  errors.length = 0;

  // 点击每个档位按钮并检查是否有 JS 错误
  for (const mode of modes) {
    const btn = await page.$(`button[data-stack="${mode}"]`);
    if (btn) {
      await btn.click();
      await page.waitForTimeout(500);
    }
  }

  results['5_JS错误检查'] = errors.length === 0 ? '✅ 无 JS 错误' : `❌ 发现 ${errors.length} 个错误: ${JSON.stringify(errors.slice(0, 3))}`;

  // 验证 JS 函数是否在全局暴露
  const fnCheck = await page.evaluate(() => {
    return {
      setLiveStackMode: typeof window.setLiveStackMode === 'function',
      startLiveStack: typeof window.startLiveStack === 'function',
      stopLiveStack: typeof window.stopLiveStack === 'function',
      saveLiveStack: typeof window.saveLiveStack === 'function',
    };
  });
  results['5_JS函数暴露'] = JSON.stringify(fnCheck);

  // === 6. API 端点 /api/v1/stack/presets ===
  try {
    const resp = await page.evaluate(async () => {
      const r = await fetch('/api/v1/stack/presets');
      return { status: r.status, ok: r.ok };
    });
    results['6_API_presets'] = `✅ HTTP ${resp.status}, ok=${resp.ok}`;

    // 获取 presets 内容
    const presetsData = await page.evaluate(async () => {
      const r = await fetch('/api/v1/stack/presets');
      return r.json();
    });
    results['6_API_presets_data'] = presetsData.success ? `✅ success=true, keys=${JSON.stringify(Object.keys(presetsData.presets))}` : `❌ success=${presetsData.success}`;
  } catch (e) {
    results['6_API_presets'] = `❌ 请求失败: ${e.message}`;
  }

  await browser.close();

  // === 输出结果 ===
  console.log('\n========== Live Stack 验证结果 ==========');
  for (const [key, val] of Object.entries(results)) {
    console.log(`  ${key}: ${val}`);
  }
  if (errors.length > 0) {
    console.log('\n⚠️ JS 错误详情:');
    errors.forEach(e => console.log(`  - ${e}`));
  }
  console.log('==========================================');
  console.log('截图已保存: test_live_stack_screenshot.png');
})();

