// Live Stack 功能验证 - HTTP 方案（无需 Playwright）
const http = require('http');

function httpGet(path) {
  return new Promise((resolve, reject) => {
    http.get(`http://localhost:10280${path}`, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, body: data }));
    }).on('error', reject);
  });
}

async function run() {
  const results = {};

  // 获取页面 HTML
  const page = await httpGet('/');
  const html = page.body;

  console.log(`\n页面 HTTP ${page.status}, 大小 ${html.length} bytes`);

  // === 1. Live Stack 控制栏是否显示 ===
  const hasLiveStackSection = html.includes('Live Stack') || html.includes('liveStack');
  results['1_LiveStack控制栏'] = hasLiveStackSection ? '✅ 存在' : '❌ 不存在';

  // === 2. 档位按钮 ===
  const modes = [
    { mode: 'off', label: '关闭' },
    { mode: '2s', label: '2s' },
    { mode: '5s', label: '5s' },
    { mode: '10s', label: '10s' },
    { mode: '30s', label: '30s' },
  ];

  for (const m of modes) {
    const hasBtn = html.includes(`data-stack="${m.mode}"`);
    const hasOnclick = html.includes(`setLiveStackMode('${m.mode}')`);
    results[`2_档位_${m.mode}`] = hasBtn && hasOnclick ? `✅ 按钮+onclick存在` : `❌ 按钮=${hasBtn} onclick=${hasOnclick}`;
  }

  // === 3. 硬件曝光输入框 ===
  const hasExposureInput = html.includes('id="hardwareExposureMs"') || html.includes('hardwareExposureMs');
  // 提取 input 完整行
  const inputMatch = html.match(/hardwareExposureMs[^<]{0,200}/);
  results['3_硬件曝光输入框'] = hasExposureInput
    ? `✅ 存在: ...${inputMatch ? inputMatch[0].substring(0, 120) : ''}...`
    : '❌ 不存在';

  // === 4. 开始/停止/保存按钮 ===
  const hasStartBtn = html.includes('id="btnLiveStackStart"') && html.includes('startLiveStack()');
  const hasStopBtn = html.includes('id="btnLiveStackStop"') && html.includes('stopLiveStack()');
  const hasSaveBtn = html.includes('id="btnLiveStackSave"') && html.includes('saveLiveStack()');

  results['4_开始按钮'] = hasStartBtn ? '✅ 存在' : '❌ 不存在';
  results['4_停止按钮'] = hasStopBtn ? '✅ 存在' : '❌ 不存在';
  results['4_保存按钮'] = hasSaveBtn ? '✅ 存在' : '❌ 不存在';

  // 检查 disabled 状态
  const startDisabled = html.includes('id="btnLiveStackStart"') && html.match(/id="btnLiveStackStart"[^>]*disabled/);
  const stopDisabled = html.includes('id="btnLiveStackStop"') && html.match(/id="btnLiveStackStop"[^>]*disabled/);
  const saveDisabled = html.includes('id="btnLiveStackSave"') && html.match(/id="btnLiveStackSave"[^>]*disabled/);

  results['4_开始_disabled'] = startDisabled ? '✅ 默认禁用(正确)' : '⚠️ 默认启用(可能不正确)';
  results['4_停止_disabled'] = stopDisabled ? '✅ 默认禁用(正确)' : '⚠️ 默认启用(可能不正确)';
  results['4_保存_disabled'] = saveDisabled ? '✅ 默认禁用(正确)' : '⚠️ 默认启用(可能不正确)';

  // === 5. JS 函数定义 ===
  const fnPatterns = [
    'function setLiveStackMode',
    'function startLiveStack',
    'function stopLiveStack',
    'function saveLiveStack',
  ];

  for (const fn of fnPatterns) {
    const hasFn = html.includes(fn);
    results[`5_JS函数_${fn}`] = hasFn ? '✅ 已定义' : '❌ 未定义';
  }

  // 检查函数是否在 window 上暴露
  const exposeLine = html.includes('setLiveStackMode, startLiveStack, stopLiveStack, saveLiveStack');
  results['5_JS函数_window暴露'] = exposeLine ? '✅ 在 window 上暴露' : '❌ 未在 window 上暴露';

  // 检查 setLiveStackMode 函数体（关键：是否调用 API）
  const setModeMatch = html.match(/function setLiveStackMode\([^)]*\)\s*\{[^}]+\}/s);
  if (setModeMatch) {
    const body = setModeMatch[0];
    const callsApi = body.includes('fetch') || body.includes('XMLHttpRequest') || body.includes('/api/');
    const updatesUI = body.includes('getElementById') || body.includes('document');
    results['5_setLiveStackMode_内容'] = `API调用=${callsApi}, UI更新=${updatesUI}`;
  }

  // === 6. API 端点 ===
  try {
    const apiResp = await httpGet('/api/v1/stack/presets');
    const apiJson = JSON.parse(apiResp.body);
    results['6_API_/stack/presets'] = `✅ HTTP ${apiResp.status}`;
    results['6_API_success字段'] = apiJson.success ? '✅ true' : `❌ ${apiJson.success}`;

    if (apiJson.presets) {
      const keys = Object.keys(apiJson.presets);
      results['6_API_presets_keys'] = `✅ ${keys.join(', ')}`;

      for (const key of modes.map(m => m.mode)) {
        const preset = apiJson.presets[key];
        if (preset) {
          results[`6_API_preset_${key}`] = `✅ exposure=${preset.exposure}, frames=${preset.frames}, label=${preset.label}`;
        } else {
          results[`6_API_preset_${key}`] = `❌ 缺失`;
        }
      }
    }
  } catch (e) {
    results['6_API_/stack/presets'] = `❌ 请求失败: ${e.message}`;
  }

  // 检查其他相关 API
  const apiPaths = [
    '/api/v1/stack/start',
    '/api/v1/stack/stop',
    '/api/v1/stack/save',
    '/api/v1/stack/status',
  ];

  for (const path of apiPaths) {
    try {
      const r = await httpGet(path);
      results[`6_API_${path}`] = `HTTP ${r.status}`;
    } catch (e) {
      results[`6_API_${path}`] = `错误: ${e.message}`;
    }
  }

  // === 输出结果 ===
  console.log('\n========== Live Stack 验证结果 ==========');
  for (const [key, val] of Object.entries(results)) {
    console.log(`  ${key}: ${val}`);
  }
  console.log('==========================================');

  // 总结
  const failures = Object.entries(results).filter(([, v]) => v.startsWith('❌'));
  if (failures.length > 0) {
    console.log(`\n⚠️  发现 ${failures.length} 个问题:`);
    failures.forEach(([k, v]) => console.log(`  ${k}: ${v}`));
  } else {
    console.log('\n✅ 所有检查通过!');
  }
}

run().catch(console.error);

